439	    public void testPerformActionWithFreshTokens_afterTokenExpiration() {
440	        AuthorizationRequest authReq = getMinimalAuthRequestBuilder("id_token token code")
441	                .setScope("my_scope")
442	                .build();
443	
444	        AuthorizationResponse authResp = new AuthorizationResponse.Builder(authReq)
445	                .setAccessToken(TEST_ACCESS_TOKEN)
446	                .setAccessTokenExpirationTime(TWO_MINUTES)
447	                .setIdToken(TEST_ID_TOKEN)
448	                .setAuthorizationCode(TEST_AUTH_CODE)
449	                .setState(authReq.state)
450	                .build();
451	        TokenResponse tokenResp = getTestAuthCodeExchangeResponse();
452	        AuthState state = new AuthState(authResp, tokenResp, null);
453	
454	        AuthorizationService service = mock(AuthorizationService.class);
455	        AuthState.AuthStateAction action = mock(AuthState.AuthStateAction.class);
456	
457	        // at this point in time, the access token will be considered to be expired
458	        mClock.currentTime.set(TWO_MINUTES - AuthState.EXPIRY_TIME_TOLERANCE_MS + ONE_SECOND);
459	        state.performActionWithFreshTokens(
460	                service,
461	                NoClientAuthentication.INSTANCE,
462	                Collections.<String, String>emptyMap(),
463	                mClock,
464	                action);
465	
466	        // as the access token has expired, we expect a token refresh request
467	        ArgumentCaptor<TokenRequest> requestCaptor = ArgumentCaptor.forClass(TokenRequest.class);
468	        ArgumentCaptor<AuthorizationService.TokenResponseCallback> callbackCaptor =
469	                ArgumentCaptor.forClass(AuthorizationService.TokenResponseCallback.class);
470	        verify(service, times(1)).performTokenRequest(
471	                requestCaptor.capture(),
472	                any(ClientAuthentication.class),
473	                callbackCaptor.capture());
474	
475	        assertThat(requestCaptor.getValue().refreshToken).isEqualTo(tokenResp.refreshToken);
476	
477	        // the action should not be executed until after the token refresh completes
478	        verifyNoInteractions(action);
479	
480	        String freshAccessToken = "fresh_access_token";
481	        Long freshExpirationTime = mClock.currentTime.get() + TWO_MINUTES;
482	        String freshIdToken = "fresh.id.token";
483	
484	        // simulate success on the token request, with fresh tokens in the result
485	        TokenResponse freshResponse = new TokenResponse.Builder(requestCaptor.getValue())
486	                .setTokenType(TokenResponse.TOKEN_TYPE_BEARER)
487	                .setAccessToken(freshAccessToken)
488	                .setAccessTokenExpirationTime(freshExpirationTime)
489	                .setIdToken(freshIdToken)
490	                .build();
491	
492	        callbackCaptor.getValue().onTokenRequestCompleted(freshResponse, null);
493	
494	        // the action should be invoked in response to the token request completion
495	        verify(action, times(1)).execute(
496	                eq(freshAccessToken),
497	                eq(freshIdToken),
498	                ArgumentMatchers.<AuthorizationException>isNull());
499	
500	        // additionally, the auth state should be updated with the new token values
501	        assertThat(state.getAccessToken()).isEqualTo(freshAccessToken);
502	        assertThat(state.getAccessTokenExpirationTime()).isEqualTo(freshExpirationTime);
503	        assertThat(state.getIdToken()).isEqualTo(freshIdToken);
504	    }
