153	     * @see "The OAuth 2.0 Authorization Framework (RFC 6749), Section 4.1.3
154	     * <https://tools.ietf.org/html/rfc6749#section-4.1.3>"
155	     */
156	    @NonNull
157	    public final String grantType;
