1	apply plugin: 'com.android.library'
2	apply plugin: 'maven-publish'
3	apply plugin: 'signing'
4	
5	apply from: '../config/android-common.gradle'
6	
7	group = GROUP
8	version = rootProject.versionName
9	
10	project.archivesBaseName = 'appauth'
11	
12	android.testOptions {
13	    unitTests.includeAndroidResources = true
14	}
15	
16	dependencies {
17	    api "androidx.browser:browser:${project.androidXVersions.browser}"
18	    implementation "androidx.annotation:annotation:${project.androidXVersions.annotation}"
19	    implementation "androidx.appcompat:appcompat:${project.androidXVersions.appCompat}"
20	    apply from: '../config/testdeps.gradle', to:it
21	}
22	
23	apply from: '../config/style.gradle'
24	apply from: '../config/coverage.gradle'
25	apply from: '../config/javadoc.gradle'
26	
27	artifacts {
28	    archives sourcesJar
29	    archives javadocJar
30	}
31	
32	publishing {
33	    publications {
34	        release(MavenPublication) {
35	            groupId GROUP
36	            artifactId POM_ARTIFACT_ID
37	            version rootProject.versionName
38	
39	            artifact("$buildDir/outputs/aar/${project.archivesBaseName}-release.aar")
40	            artifact sourcesJar
41	            artifact javadocJar
42	
43	            pom {
44	                name = POM_NAME
45	                description = POM_DESCRIPTION
46	                packaging = POM_PACKAGING
47	                url = POM_URL
48	                licenses {
49	                    license {
50	                        name = POM_LICENCE_NAME
51	                        url = POM_LICENCE_URL
52	                        distribution = POM_LICENCE_DIST
53	                    }
54	                }
55	                developers {
56	                    developer {
57	                        id = POM_DEVELOPER_ID
58	                        name = POM_DEVELOPER_NAME
59	                        url = POM_DEVELOPER_URL
60	                    }
61	                }
62	                scm {
63	                    url = POM_SCM_URL
64	                    connection = POM_SCM_CONNECTION
65	                    developerConnection = POM_SCM_DEV_CONNECTION
66	                }
67	                // A slightly hacky fix so that the POM will include transitive dependencies
68	                withXml {
69	                    def dependenciesNode = asNode().appendNode('dependencies')
70	
71	                    project.configurations.implementation.allDependencies.each {
72	                        def dependencyNode = dependenciesNode.appendNode('dependency')
73	                        dependencyNode.appendNode('groupId', it.group)
74	                        dependencyNode.appendNode('artifactId', it.name)
75	                        dependencyNode.appendNode('version', it.version)
76	                    }
77	                }
78	            }
79	        }
80	    }
81	    repositories {
82	        maven {
83	            name = "sonatype"
84	            url = "https://oss.sonatype.org/service/local/staging/deploy/maven2/"
85	            credentials {
86	                username project.hasProperty('ossrhUsername') ? ossrhUsername : ''
87	                password project.hasProperty('ossrhPassword') ? ossrhPassword : ''
88	            }
89	        }
90	    }
91	}
92	
93	signing {
94	    required { hasProperty('signing.keyId') }
95	    sign publishing.publications
96	}
