        verifyNoInteractions(service);

        // the action should have been directly invoked
        verify(action, times(1)).execute(
                eq(TEST_ACCESS_TOKEN),
                eq(TEST_ID_TOKEN),
                ArgumentMatchers.<AuthorizationException>isNull());
    }

